def f(expr: str) -> int:
    i, n = 0, len(expr)

    def skip_spaces():
        nonlocal i
        while i < n and expr[i] == ' ':
            i += 1

    def parse_number() -> int:
        nonlocal i
        skip_spaces()
        start = i
        while i < n and expr[i].isdigit():
            i += 1
        return int(expr[start:i])

    def parse_factor() -> int:
        nonlocal i
        skip_spaces()
        if i < n and expr[i] == '(':
            i += 1
            val = parse_expr()
            skip_spaces()
            if i < n and expr[i] == ')':
                i += 1
            return val
        return parse_number()

    def parse_term() -> int:
        nonlocal i
        val = parse_factor()
        while True:
            skip_spaces()
            if i < n and expr[i] == '*':
                i += 1
                val *= parse_factor()
            else:
                break
        return val

    def parse_expr() -> int:
        nonlocal i
        val = parse_term()
        while True:
            skip_spaces()
            if i < n and expr[i] in '+-':
                op = expr[i]
                i += 1
                right = parse_term()
                if op == '+':
                    val += right
                else:
                    val -= right
            else:
                break
        return val

    result = parse_expr()
    skip_spaces()
    return result
