import bisect

def f(lst):
    """Return the length of the longest strictly increasing subsequence of lst."""
    tails = []                     # tails[i] = smallest possible tail of an IS of length i+1
    for x in lst:
        # find the first tail >= x (strictly increasing => we replace the first >=)
        i = bisect.bisect_left(tails, x)
        if i == len(tails):
            tails.append(x)
        else:
            tails[i] = x
    return len(tails)
